@app.get("/health")
async def health_check():
    """Health check endpoint."""
    return JSONResponse({"status": "healthy", "timestamp": datetime.now().isoformat()})

@app.get("/server-ip")
async def server_ip():
    """Get server's outbound IP for Binance whitelisting."""
    import aiohttp
    try:
        async with aiohttp.ClientSession() as session:
            async with session.get("https://api.ipify.org?format=json", timeout=aiohttp.ClientTimeout(total=10)) as response:
                data = await response.json()
                return JSONResponse({"outbound_ip": data.get("ip"), "region": os.environ.get("FLY_REGION", "unknown")})
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)

@app.get("/api/exit-telemetry")
async def exit_telemetry():
    """Phase 255: Exit telemetry dashboard — combined engine/protection/signal stats."""
    try:
        now = time.time()
        
        # Exit engine stats
        engine_stats = exit_engine.get_stats() if exit_engine else {}
        
        # Protection manager status
        prot_status = protection_manager.get_status() if protection_manager else {}
        
        # Active signals summary
        signal_summary = {}
        for sym, sig in active_signals.items():
            age = now - sig.get('created_ts', now)
            signal_summary[sym] = {
                'side': sig.get('side'),
                'score': sig.get('score', 0),
                'age_sec': round(age, 0),
                'state': sig.get('state', 'UNKNOWN'),
                'reentry_count': sig.get('reentry_count', 0),
                'counter_count': sig.get('counter_count', 0),
                'last_close_sec_ago': round(now - sig['last_close_ts'], 0) if sig.get('last_close_ts', 0) > 0 else None,
            }
        
        # Per-reason counters from recent exit log
        reason_counts = {}
        for entry in engine_stats.get('recent_exits', []):
            r = entry.get('reason', 'UNKNOWN')
            reason_counts[r] = reason_counts.get(r, 0) + 1
        
        return JSONResponse({
            'exit_engine': {
                'total': engine_stats.get('total', 0),
                'skipped': engine_stats.get('skipped', 0),
                'upgraded': engine_stats.get('upgraded', 0),
                'reason_counts': reason_counts,
                'recent_exits': engine_stats.get('recent_exits', []),
            },
            'protection': prot_status,
            'active_signals': signal_summary,
            'signal_count': len(signal_summary),
            'data_health': data_provider.get_health() if data_provider else {},
            'timestamp': datetime.now().isoformat(),
        })
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)

# Phase 16: Global Paper Trader for REST API access
global_paper_trader = PaperTradingEngine()

# ============================================================================
# Phase 251: EXIT DECISION ENGINE
# Unified exit gate — all close paths go through request_exit()
# Provides: double-close prevention, priority override, reason normalization
# ============================================================================

class ExitDecisionEngine:
    """Phase 251: Unified exit decision gate.
    
    All close paths call request_exit() instead of close_position() directly.
    Provides:
    - exit_pending guard (double-close prevention per symbol)
    - priority-based exit override (EMERGENCY > TRAIL > TP > TIME)
    - close_reason normalization & source tracking
    - telemetry logging for exit decisions
    """
    EXIT_PRIORITY = {
        'EMERGENCY_SL': 100,
        'KILL_SWITCH': 95,
        'RECOVERY_CLOSE_ALL': 93,
        'RECOVERY_EXIT': 90,
        'PROTECTION_LOCK': 85,
        'FAILED_CONTINUATION': 70,
        'TRAIL_EXIT': 60,
        'TP_HIT': 50,
        'TIME_GRADUAL': 40,
        'TIME_EXIT': 35,
    }
    
    def __init__(self, paper_trader):
        self.paper_trader = paper_trader
        self.exit_inflight = {}   # Phase 261: symbol -> {started_at, reason, source, trace_id}
        self._exit_log = []       # last N exit decisions for telemetry
        self._stats = {'total': 0, 'skipped': 0, 'upgraded': 0}

    def _normalize_reason(self, reason: str) -> tuple:
        reason_upper = reason.upper()
        if 'TRAIL_TIMEOUT' in reason_upper: return 'TRAIL_TIMEOUT', 'TIME'
        if 'ERROR_TIMEOUT' in reason_upper: return 'EXEC_TIMEOUT', 'TIME'
        if 'TIMEOUT' in reason_upper: return 'TIMEOUT', 'TIME'
        if 'TIME' in reason_upper: return 'TIME_EXIT', 'TIME'
        if 'TP_HIT' in reason_upper: return 'TP_HIT', 'PROFIT'
        if 'SL_HIT' in reason_upper: return 'SL_HIT', 'LOSS'
        if 'EMERGENCY_SL' in reason_upper: return 'EMERGENCY_SL', 'LOSS'
        if 'KILL_SWITCH' in reason_upper: return 'KILL_SWITCH', 'LOSS'
        if 'TRAIL' in reason_upper: return 'TRAIL_EXIT', 'PROFIT'
        return reason_upper.split('(')[0].strip(), 'OTHER'
    
    def request_exit(self, pos, exit_price: float, reason: str, source: str = 'UNKNOWN'):
        """Request position exit through unified gate.
        
        Args:
            pos: Position dict
            exit_price: Exit price
            reason: Close reason string
            source: Caller identifier (SCANNER, WEBSOCKET, FAST_UPDATER, etc.)
        
        Returns: trade dict or None if skipped
        """
        symbol = pos.get('symbol', '')
        reason_norm, reason_class = self._normalize_reason(reason)
        now = time.time()
        age_sec = now - (pos.get('openTime', now * 1000) / 1000)
        
        hold_prob = 0.5
        aggr = 0.5
        deferred = False
        defer_sec = 0
        
        if EXIT_FORECAST_ENABLED and reason_norm not in EXIT_FORECAST_BLOCK_REASONS and age_sec >= EXIT_FORECAST_HOLD_MIN_SEC:
            deferred_until = pos.get('_exit_deferred_until', 0)
            if now < deferred_until:
                self._stats['skipped'] += 1
                return None
                
            features = exit_forecast_model.build_exit_features(pos, exit_price, reason_norm, source)
            hold_prob = exit_forecast_model.predict_hold_prob(features)
            aggr = exit_forecast_model.predict_exit_aggressiveness(features)
            
            if hold_prob >= EXIT_FORECAST_MIN_HOLD_PROB and reason_class in ['TIME', 'MOMENTUM', 'OTHER']:
                pos['_exit_deferred_until'] = now + EXIT_FORECAST_MAX_DELAY_SEC
                pos['_exit_deferred_count'] = pos.get('_exit_deferred_count', 0) + 1
                self._stats['skipped'] += 1
                defer_sec = EXIT_FORECAST_MAX_DELAY_SEC
                logger.info(f"⏳ EXIT_DEFER_FORECAST: {symbol} {reason_norm} hold_prob={hold_prob:.2f}. Deferring for {defer_sec}s.")
                self._exit_log.append({
                    'symbol': symbol, 'reason': reason, 'reason_norm': reason_norm, 'reason_class': reason_class,
                    'source': source, 'ts': now, 'trace_id': f"DEFER_{symbol}_{int(now*1000)}",
                    'hold_prob': round(hold_prob, 3), 'aggressiveness': round(aggr, 3), 
                    'deferred': True, 'defer_seconds': defer_sec, 'position_age_sec': round(age_sec, 1)
                })
                return None

        # Phase 261: Symbol-level exit lock (exit_inflight)
        # Lock check comes AFTER defer logic
        if symbol in self.exit_inflight:
            existing = self.exit_inflight[symbol]
            logger.warning(
                f"⏭️ EXIT_SKIP (LOCKED): {symbol} already inflight "
                f"({existing['reason']}) since {existing['started_at']}. Ignoring {reason} from {source}."
            )
            self._stats['skipped'] += 1
            return None
        
        # Mark as pending
        trace_id = f"EXIT_{symbol}_{int(time.time()*1000)}"
        self.exit_inflight[symbol] = {
            'started_at': time.time(),
            'reason': reason,
            'source': source,
            'trace_id': trace_id
        }
        
        # Pass forecast params to trade record
        pos['exitForecastHoldProb'] = hold_prob
        pos['exitForecastAggressiveness'] = aggr
        pos['exitReasonNorm'] = reason_norm
        
        # Execute close through paper trader
        self._stats['total'] += 1
        try:
            logger.info(
                f"🚪 [LOCK_ACQUIRED] EXIT_ENGINE: {symbol} | trace_id={trace_id} "
                f"reason={reason} price={exit_price:.6f} source={source}"
            )
            # Pass trace_id down to paper_trader
            result = self.paper_trader.close_position(pos, exit_price, reason, trace_id=trace_id, source=source)
        except Exception as e:
            logger.error(f"❌ EXIT_ENGINE error: {symbol} {reason} - {e}")
            self.clear_lock(symbol, trace_id)
            result = None
        
        # Track last 50 exits for telemetry
        self._exit_log.append({
            'symbol': symbol, 'reason': reason, 'reason_norm': reason_norm, 'reason_class': reason_class,
            'source': source, 'ts': time.time(),
            'trace_id': trace_id,
            'hold_prob': round(hold_prob, 3), 'aggressiveness': round(aggr, 3),
            'deferred': False, 'defer_seconds': 0, 'position_age_sec': round(age_sec, 1)
        })
        if len(self._exit_log) > 50:
            self._exit_log = self._exit_log[-50:]
        
        return result

    def clear_lock(self, symbol: str, trace_id: str = None):
        """Phase 261: Safely clear the inflight lock, optionally verifying trace_id."""
        if symbol in self.exit_inflight:
            if trace_id is None or self.exit_inflight[symbol].get('trace_id') == trace_id:
                del self.exit_inflight[symbol]
                logger.info(f"🔓 [LOCK_RELEASED] {symbol} | trace_id={trace_id}")

    def is_exit_pending(self, symbol: str) -> bool:
        """Check if a symbol has an exit already in progress."""
        return symbol in self.exit_inflight
    
    def _get_priority(self, reason: str) -> int:
        reason_upper = reason.upper()
        for key, pri in self.EXIT_PRIORITY.items():
            if key in reason_upper:
                return pri
        return 30  # default low priority
    
    def get_stats(self) -> dict:
        return {**self._stats, 'pending': list(self.exit_inflight.keys()), 'recent_exits': self._exit_log[-20:]}

exit_engine = ExitDecisionEngine(global_paper_trader)

# ============================================================================
# Phase 254: PROTECTION MANAGER (Freqtrade-inspired)
# Lookback + stoploss streak + cooldown + pair/global lock
# ============================================================================

class ProtectionManager:
    """Phase 254: Trade protection gate.
    
    Blocks new signal entries based on:
    - Stoploss streak per pair: N consecutive SL hits → pair lock
    - Global stoploss streak: M consecutive SL hits across all pairs → global lock
    - Cooldown after lock expiry
    """
    
    def __init__(self, paper_trader):
        self.paper_trader = paper_trader
        self._pair_locks = {}    # symbol → {'until': timestamp, 'reason': str}
        self._global_lock = None  # {'until': timestamp, 'reason': str} or None
        
        # Configurable thresholds
        self.LOOKBACK_WINDOW_SEC = 1800    # 30 min lookback
        self.PAIR_SL_STREAK_LIMIT = 3     # 3 consecutive SL on same pair → lock
        self.GLOBAL_SL_STREAK_LIMIT = 5   # 5 consecutive SL globally → lock
        self.PAIR_LOCK_DURATION_SEC = 600  # 10 min pair lock
        self.GLOBAL_LOCK_DURATION_SEC = 900  # 15 min global lock
    
    def should_block_signal(self, symbol: str, action: str) -> tuple:
        """Check if a signal should be blocked.
        
        Returns: (blocked: bool, reason: str)
        """
        now = time.time()
        
        # Check global lock
        if self._global_lock and now < self._global_lock['until']:
            remaining = self._global_lock['until'] - now
            reason = f"PROTECTION_LOCK:GLOBAL_SL_STREAK ({remaining:.0f}s remaining)"
            return True, reason
        elif self._global_lock:
            self._global_lock = None  # Expired
        
        # Check pair lock
        if symbol in self._pair_locks:
            lock = self._pair_locks[symbol]
            if now < lock['until']:
                remaining = lock['until'] - now
                reason = f"PROTECTION_LOCK:{symbol}_SL_STREAK ({remaining:.0f}s remaining)"
                return True, reason
            else:
                del self._pair_locks[symbol]  # Expired
        
        # Analyze recent trade history
        self._check_streaks(now)
        
        # Re-check after analysis (streak check may have created new locks)
        if self._global_lock and now < self._global_lock['until']:
            remaining = self._global_lock['until'] - now
            return True, f"PROTECTION_LOCK:GLOBAL_SL_STREAK ({remaining:.0f}s remaining)"
        
        if symbol in self._pair_locks:
            lock = self._pair_locks[symbol]
            if now < lock['until']:
                remaining = lock['until'] - now
                return True, f"PROTECTION_LOCK:{symbol}_SL_STREAK ({remaining:.0f}s remaining)"
        
        return False, ''
    
    def _check_streaks(self, now: float):
        """Analyze recent trades for stoploss streaks."""
        cutoff = now - self.LOOKBACK_WINDOW_SEC
        
        # Get recent trades from paper trader
        recent_trades = []
        for trade in reversed(self.paper_trader.trades):  # Phase 257: was trade_history (wrong attr → trades)
            close_time = trade.get('closeTime', 0) / 1000  # ms → s
            if close_time < cutoff:
                break
            recent_trades.append(trade)
        
        if not recent_trades:
            return
        
        # Check per-pair streaks
        pair_trades = {}
        for trade in recent_trades:
            sym = trade.get('symbol', '')
            if sym not in pair_trades:
                pair_trades[sym] = []
            pair_trades[sym].append(trade)
        
        for sym, trades in pair_trades.items():
            # Count consecutive SL from most recent
            sl_streak = 0
            for t in trades:  # Already reverse chronological
                reason = (t.get('reason', '') or '').upper()
                if 'SL_HIT' in reason or 'EMERGENCY_SL' in reason:
                    sl_streak += 1
                else:
                    break
            
            if sl_streak >= self.PAIR_SL_STREAK_LIMIT and sym not in self._pair_locks:
                self._pair_locks[sym] = {
                    'until': now + self.PAIR_LOCK_DURATION_SEC,
                    'reason': f"PAIR_SL_STREAK:{sl_streak}",
                }
                logger.warning(f"🔒 PROTECTION_LOCK: {sym} locked for {self.PAIR_LOCK_DURATION_SEC}s (SL streak={sl_streak})")
        
        # Check global streak
        global_sl_streak = 0
        all_trades_sorted = sorted(recent_trades, key=lambda t: t.get('closeTime', 0), reverse=True)
        for t in all_trades_sorted:
            reason = (t.get('reason', '') or '').upper()
            if 'SL_HIT' in reason or 'EMERGENCY_SL' in reason:
                global_sl_streak += 1
            else:
                break
        
        if global_sl_streak >= self.GLOBAL_SL_STREAK_LIMIT and not self._global_lock:
            self._global_lock = {
                'until': now + self.GLOBAL_LOCK_DURATION_SEC,
                'reason': f"GLOBAL_SL_STREAK:{global_sl_streak}",
            }
            logger.warning(f"🔒 PROTECTION_LOCK: GLOBAL locked for {self.GLOBAL_LOCK_DURATION_SEC}s (SL streak={global_sl_streak})")
    
    def get_status(self) -> dict:
        now = time.time()
        active_pair_locks = {
            sym: {'remaining': lock['until'] - now, 'reason': lock['reason']}
            for sym, lock in self._pair_locks.items()
            if now < lock['until']
        }
        return {
            'global_locked': self._global_lock is not None and now < self._global_lock.get('until', 0),
            'global_remaining': max(0, self._global_lock['until'] - now) if self._global_lock else 0,
            'pair_locks': active_pair_locks,
        }

protection_manager = ProtectionManager(global_paper_trader)

# ============================================================================
# Phase 256: DATA PROVIDER LAYER
# OHLCV cache + freshness + missing-candle validation + health telemetry
# ============================================================================

class DataProvider:
    """Phase 256: Centralized data access with cache, freshness, and health.
    
    Features:
    - TTL-based OHLCV cache: avoids redundant exchange calls
    - Freshness validation: detects stale data (last candle too old)
    - Missing candle detection: gaps in expected candle sequence
    - Health telemetry: hit/miss/stale counters per (symbol, timeframe)
    """
    
    # Timeframe → expected candle interval in seconds
    TF_INTERVAL_SEC = {
        '1m': 60, '3m': 180, '5m': 300, '15m': 900,
        '30m': 1800, '1h': 3600, '2h': 7200, '4h': 14400,
        '6h': 21600, '8h': 28800, '12h': 43200, '1d': 86400,
    }
    
    # Timeframe → cache TTL (how long to reuse cached data)
    TF_CACHE_TTL_SEC = {
        '1m': 30, '3m': 60, '5m': 120, '15m': 300,
        '30m': 600, '1h': 900, '4h': 1800, '1d': 3600,
    }
    
    # Staleness threshold: candle older than N * interval → stale
    STALENESS_MULTIPLIER = 3.0
    
    def __init__(self):
        self._cache = {}  # (symbol, tf) → {'data': list, 'ts': float, 'limit': int}
        self._health = {}  # (symbol, tf) → {'hits': 0, 'misses': 0, 'stale': 0, 'missing': 0}
    
    async def get_ohlcv(self, exchange, symbol: str, timeframe: str, limit: int = 100) -> list:
        """Fetch OHLCV data with caching and freshness checks.
        
        Returns: list of candles (same format as exchange.fetch_ohlcv)
        """
        key = (symbol, timeframe)
        now = time.time()
        ttl = self.TF_CACHE_TTL_SEC.get(timeframe, 300)
        
        # Init health counters
        if key not in self._health:
            self._health[key] = {'hits': 0, 'misses': 0, 'stale': 0, 'missing': 0, 'last_fetch_ts': 0}
        
        # Check cache
        cached = self._cache.get(key)
        if cached and (now - cached['ts']) < ttl and cached['limit'] >= limit:
            self._health[key]['hits'] += 1
            return cached['data']
        
        # Cache miss → fetch from exchange
        self._health[key]['misses'] += 1
        try:
            data = await exchange.fetch_ohlcv(symbol, timeframe, limit=limit)
            self._cache[key] = {'data': data, 'ts': now, 'limit': limit}
            self._health[key]['last_fetch_ts'] = now
            
            # Freshness check
            if data:
                self._check_freshness(key, data, timeframe, now)
            
            return data
        except Exception as e:
            logger.warning(f"📊 DATAPROVIDER: fetch failed {symbol} {timeframe}: {e}")
            # Return stale cache if available
            if cached:
                self._health[key]['stale'] += 1
                logger.info(f"📊 DATAPROVIDER: returning stale cache for {symbol} {timeframe}")
                return cached['data']
            return []
    
    def _check_freshness(self, key: tuple, data: list, timeframe: str, now: float):
        """Check if the latest candle is fresh enough."""
        interval = self.TF_INTERVAL_SEC.get(timeframe, 300)
        last_candle_ts = data[-1][0] / 1000  # ms → s
        age = now - last_candle_ts
        threshold = interval * self.STALENESS_MULTIPLIER
        
        if age > threshold:
            self._health[key]['stale'] += 1
            logger.warning(
                f"📊 DATAPROVIDER_STALE: {key[0]} {timeframe} "
                f"last_candle={age:.0f}s ago (threshold={threshold:.0f}s)"
            )
        
        # Missing candle detection: check gaps
        if len(data) >= 3:
            expected_gap = interval * 1000  # ms
            gaps = 0
            for i in range(1, min(10, len(data))):
                actual_gap = data[i][0] - data[i-1][0]
                if actual_gap > expected_gap * 1.5:  # Allow 50% tolerance
                    gaps += 1
            if gaps > 0:
                self._health[key]['missing'] += gaps
    
    def is_data_stale(self, symbol: str, timeframe: str) -> bool:
        """Check if cached data for a symbol/tf is considered stale."""
        key = (symbol, timeframe)
        cached = self._cache.get(key)
        if not cached or not cached['data']:
            return True
        
        interval = self.TF_INTERVAL_SEC.get(timeframe, 300)
        last_ts = cached['data'][-1][0] / 1000
        age = time.time() - last_ts
        return age > interval * self.STALENESS_MULTIPLIER
    
    def get_score_penalty(self, symbol: str, timeframe: str = '5m') -> float:
        """Get a score penalty factor (0.0-1.0) based on data freshness.
        
        Returns 1.0 (no penalty) if data is fresh, lower values if stale.
        """
        key = (symbol, timeframe)
        cached = self._cache.get(key)
        if not cached or not cached['data']:
            return 0.7  # No data → moderate penalty
        
        interval = self.TF_INTERVAL_SEC.get(timeframe, 300)
        last_ts = cached['data'][-1][0] / 1000
        age = time.time() - last_ts
        
        if age <= interval * 1.5:
            return 1.0  # Fresh
        elif age <= interval * 3.0:
            return 0.9  # Slightly stale
        elif age <= interval * 6.0:
            return 0.75  # Stale
        else:
            return 0.5  # Very stale
    
    def get_health(self) -> dict:
        """Get data health telemetry for all tracked symbols/timeframes."""
        now = time.time()
        result = {}
        for (sym, tf), stats in self._health.items():
            cache_entry = self._cache.get((sym, tf))
            cache_age = round(now - cache_entry['ts'], 0) if cache_entry else None
            result[f"{sym}:{tf}"] = {
                **stats,
                'cache_age_sec': cache_age,
                'is_stale': self.is_data_stale(sym, tf),
            }
        return result
    
    def invalidate(self, symbol: str = None, timeframe: str = None):
        """Invalidate cache entries. If symbol is None, invalidate all."""
        if symbol is None:
            self._cache.clear()
            return
        keys_to_remove = [
            k for k in self._cache
            if k[0] == symbol and (timeframe is None or k[1] == timeframe)
        ]
        for k in keys_to_remove:
            del self._cache[k]

data_provider = DataProvider()

# Phase 138: Global dictionary to track close reasons for Binance sync
# When engine triggers SL/TP/Trail, reason is stored here instead of writing to trade history
# Binance sync will use this to set proper reason when detecting closed position
pending_close_reasons = {}  # {symbol: {"reason": str, "details": dict, "timestamp": int}}

# Phase 252: Active signal lifecycle tracking
# Signals persist until invalidated by confirmed counter-signal
active_signals = {}  # {symbol: {side, score, created_ts, last_refresh_ts, ttl_sec, state, counter_count, counter_first_ts, reentry_count, last_close_ts}}

def get_persistent_active_signals_snapshot(now_ts: Optional[float] = None) -> list:
    """
    Build UI snapshot of ACTIVE signals and prune stale entries by TTL.

    TTL is measured from last refresh when available; otherwise created time.
    """
    if now_ts is None:
        now_ts = datetime.now().timestamp()

    if 'active_signals' not in globals():
        return []

    persistent_signals = []
    stale_symbols = []

    for sym, sig in list(active_signals.items()):
        if sig.get('state') != 'ACTIVE':
            continue

        anchor_ts = sig.get('last_refresh_ts') or sig.get('created_ts') or now_ts
        age = max(0, now_ts - anchor_ts)
        if age > PERSISTENT_SIGNAL_TTL_SEC:
            stale_symbols.append(sym)
            continue

        persistent_signals.append({
            "symbol": sym,
            "signalAction": sig.get('side', 'NONE'),
            "signalScore": sig.get('score', 0),
            "createdTs": sig.get('created_ts', 0),
            "lastRefreshTs": sig.get('last_refresh_ts', 0),
            "state": sig.get('state'),
            "counterCount": sig.get('counter_count', 0),
            "reentryCount": sig.get('reentry_count', 0),
            "lastCloseTs": sig.get('last_close_ts', 0),
            "ageSec": age
        })

    for sym in stale_symbols:
        sig = active_signals.get(sym)
        if sig and sig.get('state') == 'ACTIVE':
            logger.info(
                f"⌛ SIGNAL_EXPIRED_SNAPSHOT: {sym} {sig.get('side')} > {PERSISTENT_SIGNAL_TTL_SEC}s (UI prune)"
            )
            active_signals.pop(sym, None)

    return persistent_signals

